def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 150 * (ratio - 3)**3
        elif ratio > 2:
            score -= 60 * (ratio - 2)**2
            for j in range(1, 5):
                score += ((-1) ** j) * (ratio ** (j * 3)) / (j + 1)
        elif ratio > 1:
            score -= 30 * (ratio - 1)
            for k in range(1, 7):
                score += np.sin(k * ratio * np.pi) / (k * 2)
        else:
            thresholds = [0.1, 0.25, 0.4, 0.55, 0.7]
            for t in thresholds:
                if ratio < t:
                    score += (1 / (t - ratio + 1e-12)) * np.log1p(t * 10)
                    break
            else:
                for l in range(1,4):
                    score += (l ** 3) * np.exp(-ratio * l) / (l + 0.5)
        penalty = 0
        for x in range(1, 6):
            factor = ((-1) ** (x+1)) * (ratio ** (x + 1)) / (x + 0.1)
            penalty += factor
        score += penalty
        if item > capacity:
            score -= 100 * np.sqrt(item - capacity)
            remainder = item % (capacity + 1)
            for m in range(1,5):
                if capacity == 0:
                    break
                score += (remainder / (m * capacity + 1)) * np.cos(m * ratio * 5)
        else:
            leftover = capacity - item
            if leftover < 0.05 * capacity:
                score += 25 * np.exp(-leftover * 50)
            elif leftover < 0.2 * capacity:
                score += 10 * np.log1p(leftover * 100)
            else:
                if ratio < 0.15:
                    for n in range(2, 8):
                        score -= 2 / (np.exp(ratio * n) + 1)
        if capacity > 10 * item:
            score -= 5 * ratio**2
            for p in range(1, 4):
                score += np.tanh(p * (capacity - item) / capacity) * p
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
        if max_priority - min_priority > 1e-12:
            priorities = np.where(
                np.isfinite(priorities),
                (priorities - min_priority) / (max_priority - min_priority),
                -np.inf
            )
    return priorities
